-- Create "discord_servers" table
CREATE TABLE "discord_servers" ("id" character varying NOT NULL, PRIMARY KEY ("id"));
-- Create "channels_for_courses" table
CREATE TABLE "channels_for_courses" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "name" character varying NOT NULL, "teacher_channel_id" character varying NOT NULL, "student_channel_id" character varying NOT NULL, "queue_channel_id" character varying NOT NULL, "channels_for_course_discord_server" character varying NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "channels_for_courses_discord_servers_discord_server" FOREIGN KEY ("channels_for_course_discord_server") REFERENCES "discord_servers" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- Create index "channels_for_courses_queue_channel_id_key" to table: "channels_for_courses"
CREATE UNIQUE INDEX "channels_for_courses_queue_channel_id_key" ON "channels_for_courses" ("queue_channel_id");
-- Create index "channels_for_courses_student_channel_id_key" to table: "channels_for_courses"
CREATE UNIQUE INDEX "channels_for_courses_student_channel_id_key" ON "channels_for_courses" ("student_channel_id");
-- Create index "channels_for_courses_teacher_channel_id_key" to table: "channels_for_courses"
CREATE UNIQUE INDEX "channels_for_courses_teacher_channel_id_key" ON "channels_for_courses" ("teacher_channel_id");
-- Create index "channelsforcourse_name_channels_for_course_discord_server" to table: "channels_for_courses"
CREATE UNIQUE INDEX "channelsforcourse_name_channels_for_course_discord_server" ON "channels_for_courses" ("name", "channels_for_course_discord_server");
-- Create "mark_tables" table
CREATE TABLE "mark_tables" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "name" character varying NOT NULL, "spreadsheet_id" character varying NOT NULL, PRIMARY KEY ("id"));
-- Create "course_instances" table
CREATE TABLE "course_instances" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "name" character varying NOT NULL, "queues_spreadsheet_id" character varying NOT NULL, "channels_for_course_course_instance" bigint NOT NULL, "discord_server_course_instances" character varying NOT NULL, "mark_table_course_instance" bigint NULL, PRIMARY KEY ("id"), CONSTRAINT "course_instances_channels_for_courses_course_instance" FOREIGN KEY ("channels_for_course_course_instance") REFERENCES "channels_for_courses" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "course_instances_discord_servers_course_instances" FOREIGN KEY ("discord_server_course_instances") REFERENCES "discord_servers" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "course_instances_mark_tables_course_instance" FOREIGN KEY ("mark_table_course_instance") REFERENCES "mark_tables" ("id") ON UPDATE NO ACTION ON DELETE SET NULL);
-- Create index "course_instances_channels_for_course_course_instance_key" to table: "course_instances"
CREATE UNIQUE INDEX "course_instances_channels_for_course_course_instance_key" ON "course_instances" ("channels_for_course_course_instance");
-- Create index "course_instances_mark_table_course_instance_key" to table: "course_instances"
CREATE UNIQUE INDEX "course_instances_mark_table_course_instance_key" ON "course_instances" ("mark_table_course_instance");
-- Create index "courseinstance_name_discord_server_course_instances" to table: "course_instances"
CREATE UNIQUE INDEX "courseinstance_name_discord_server_course_instances" ON "course_instances" ("name", "discord_server_course_instances");
-- Create "criterions" table
CREATE TABLE "criterions" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "name" character varying NOT NULL, "course_instance_criteria" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "criterions_course_instances_criteria" FOREIGN KEY ("course_instance_criteria") REFERENCES "course_instances" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- Create index "criterion_name_course_instance_criteria" to table: "criterions"
CREATE UNIQUE INDEX "criterion_name_course_instance_criteria" ON "criterions" ("name", "course_instance_criteria");
-- Create "discord_channels" table
CREATE TABLE "discord_channels" ("id" character varying NOT NULL, "discord_server_discord_channels" character varying NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "discord_channels_discord_servers_discord_channels" FOREIGN KEY ("discord_server_discord_channels") REFERENCES "discord_servers" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- Create "mark_table_tabs" table
CREATE TABLE "mark_table_tabs" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "name" character varying NOT NULL, "sheet_id" bigint NOT NULL, "mark_table_tab_mark_table" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "mark_table_tabs_mark_tables_mark_table" FOREIGN KEY ("mark_table_tab_mark_table") REFERENCES "mark_tables" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- Create "queue_templates" table
CREATE TABLE "queue_templates" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "name" character varying NOT NULL, "sign_up_lead_time" bigint NOT NULL, "queue_template_course_instance" bigint NOT NULL, "queue_template_mark_table_tab" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "queue_templates_course_instances_course_instance" FOREIGN KEY ("queue_template_course_instance") REFERENCES "course_instances" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "queue_templates_mark_table_tabs_mark_table_tab" FOREIGN KEY ("queue_template_mark_table_tab") REFERENCES "mark_table_tabs" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- Create index "queuetemplate_name_queue_template_course_instance" to table: "queue_templates"
CREATE UNIQUE INDEX "queuetemplate_name_queue_template_course_instance" ON "queue_templates" ("name", "queue_template_course_instance");
-- Create "queues" table
CREATE TABLE "queues" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "name" character varying NOT NULL, "sign_up_lead_time" bigint NOT NULL, "sign_up_started" boolean NOT NULL DEFAULT false, "start_time" timestamptz NULL, "queue_started" boolean NOT NULL DEFAULT false, "end_time" timestamptz NULL, "queue_ended" boolean NOT NULL DEFAULT false, "simple_queue" boolean NOT NULL DEFAULT false, "sheet_id" bigint NULL, "queue_queue_template" bigint NOT NULL, "queue_mark_table_tab" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "queues_mark_table_tabs_mark_table_tab" FOREIGN KEY ("queue_mark_table_tab") REFERENCES "mark_table_tabs" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "queues_queue_templates_queue_template" FOREIGN KEY ("queue_queue_template") REFERENCES "queue_templates" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- Create "queue_places" table
CREATE TABLE "queue_places" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "position" bigint NOT NULL, "note" character varying NOT NULL, "queue_places" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "queue_places_queues_places" FOREIGN KEY ("queue_places") REFERENCES "queues" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- Create "users" table
CREATE TABLE "users" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "name" character varying NOT NULL, "discord_id" character varying NOT NULL, "is_busy" boolean NOT NULL DEFAULT false, PRIMARY KEY ("id"));
-- Create index "users_discord_id_key" to table: "users"
CREATE UNIQUE INDEX "users_discord_id_key" ON "users" ("discord_id");
-- Create "examiners" table
CREATE TABLE "examiners" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "note" character varying NULL, "queue_id" bigint NOT NULL, "teacher_id" bigint NOT NULL, "examiner_current_queue_place" bigint NULL, PRIMARY KEY ("id"), CONSTRAINT "examiners_queue_places_current_queue_place" FOREIGN KEY ("examiner_current_queue_place") REFERENCES "queue_places" ("id") ON UPDATE NO ACTION ON DELETE RESTRICT, CONSTRAINT "examiners_queues_queue" FOREIGN KEY ("queue_id") REFERENCES "queues" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "examiners_users_teacher" FOREIGN KEY ("teacher_id") REFERENCES "users" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- Create index "examiner_queue_id_teacher_id" to table: "examiners"
CREATE UNIQUE INDEX "examiner_queue_id_teacher_id" ON "examiners" ("queue_id", "teacher_id");
-- Create "examiner_criteria" table
CREATE TABLE "examiner_criteria" ("examiner_id" bigint NOT NULL, "criterion_id" bigint NOT NULL, PRIMARY KEY ("examiner_id", "criterion_id"), CONSTRAINT "examiner_criteria_criterion_id" FOREIGN KEY ("criterion_id") REFERENCES "criterions" ("id") ON UPDATE NO ACTION ON DELETE CASCADE, CONSTRAINT "examiner_criteria_examiner_id" FOREIGN KEY ("examiner_id") REFERENCES "examiners" ("id") ON UPDATE NO ACTION ON DELETE CASCADE);
-- Create "marks" table
CREATE TABLE "marks" ("value" character varying NOT NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "user_id" bigint NOT NULL, "criterion_id" bigint NOT NULL, "updated_by_exam_id" bigint NULL, PRIMARY KEY ("user_id", "criterion_id"), CONSTRAINT "marks_criterions_criterion" FOREIGN KEY ("criterion_id") REFERENCES "criterions" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "marks_users_student" FOREIGN KEY ("user_id") REFERENCES "users" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "marks_users_updated_by" FOREIGN KEY ("updated_by_exam_id") REFERENCES "users" ("id") ON UPDATE NO ACTION ON DELETE SET NULL);
-- Create "queue_criteria" table
CREATE TABLE "queue_criteria" ("queue_id" bigint NOT NULL, "criterion_id" bigint NOT NULL, PRIMARY KEY ("queue_id", "criterion_id"), CONSTRAINT "queue_criteria_criterion_id" FOREIGN KEY ("criterion_id") REFERENCES "criterions" ("id") ON UPDATE NO ACTION ON DELETE CASCADE, CONSTRAINT "queue_criteria_queue_id" FOREIGN KEY ("queue_id") REFERENCES "queues" ("id") ON UPDATE NO ACTION ON DELETE CASCADE);
-- Create "queue_place_criterions" table
CREATE TABLE "queue_place_criterions" ("passed" boolean NOT NULL, "queue_place_id" bigint NOT NULL, "criterion_id" bigint NOT NULL, PRIMARY KEY ("queue_place_id", "criterion_id"), CONSTRAINT "queue_place_criterions_criterions_criterion" FOREIGN KEY ("criterion_id") REFERENCES "criterions" ("id") ON UPDATE NO ACTION ON DELETE CASCADE, CONSTRAINT "queue_place_criterions_queue_places_queue_place" FOREIGN KEY ("queue_place_id") REFERENCES "queue_places" ("id") ON UPDATE NO ACTION ON DELETE CASCADE);
-- Create "queue_place_team" table
CREATE TABLE "queue_place_team" ("queue_place_id" bigint NOT NULL, "user_id" bigint NOT NULL, PRIMARY KEY ("queue_place_id", "user_id"), CONSTRAINT "queue_place_team_queue_place_id" FOREIGN KEY ("queue_place_id") REFERENCES "queue_places" ("id") ON UPDATE NO ACTION ON DELETE CASCADE, CONSTRAINT "queue_place_team_user_id" FOREIGN KEY ("user_id") REFERENCES "users" ("id") ON UPDATE NO ACTION ON DELETE CASCADE);
-- Create "queue_template_criteria" table
CREATE TABLE "queue_template_criteria" ("queue_template_id" bigint NOT NULL, "criterion_id" bigint NOT NULL, PRIMARY KEY ("queue_template_id", "criterion_id"), CONSTRAINT "queue_template_criteria_criterion_id" FOREIGN KEY ("criterion_id") REFERENCES "criterions" ("id") ON UPDATE NO ACTION ON DELETE CASCADE, CONSTRAINT "queue_template_criteria_queue_template_id" FOREIGN KEY ("queue_template_id") REFERENCES "queue_templates" ("id") ON UPDATE NO ACTION ON DELETE CASCADE);
